import React, { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { AuthContext } from '../context/AuthContext';
import { format } from 'date-fns';
import './Booking.css';

const Booking = () => {
  const { carId } = useParams();
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const [car, setCar] = useState(null);
  const [loading, setLoading] = useState(true);
  const [formData, setFormData] = useState({
    pickupDate: '',
    dropoffDate: '',
    pickupLocation: '',
    dropoffLocation: '',
    extras: []
  });
  const [totalPrice, setTotalPrice] = useState(0);
  const [error, setError] = useState('');

  const extras = [
    { name: 'GPS Navigation', price: 10 },
    { name: 'Child Seat', price: 15 },
    { name: 'Additional Insurance', price: 25 }
  ];

  useEffect(() => {
    fetchCarDetails();
  }, [carId]);

  useEffect(() => {
    calculateTotal();
  }, [formData, car]);

  const fetchCarDetails = async () => {
    try {
      const res = await axios.get(`http://localhost:5000/api/cars/${carId}`);
      setCar(res.data.data);
      setFormData(prev => ({
        ...prev,
        pickupLocation: res.data.data.branchId?.city || '',
        dropoffLocation: res.data.data.branchId?.city || ''
      }));
    } catch (error) {
      console.error('Error fetching car:', error);
    } finally {
      setLoading(false);
    }
  };

  const calculateTotal = () => {
    if (!car || !formData.pickupDate || !formData.dropoffDate) return;

    const days = Math.ceil(
      (new Date(formData.dropoffDate) - new Date(formData.pickupDate)) / (1000 * 60 * 60 * 24)
    );

    if (days <= 0) {
      setTotalPrice(0);
      return;
    }

    const carTotal = car.pricePerDay * days;
    const extrasTotal = formData.extras.reduce((sum, extra) => sum + extra.price * days, 0);
    setTotalPrice(carTotal + extrasTotal);
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleExtraToggle = (extra) => {
    const exists = formData.extras.find(e => e.name === extra.name);
    if (exists) {
      setFormData({
        ...formData,
        extras: formData.extras.filter(e => e.name !== extra.name)
      });
    } else {
      setFormData({
        ...formData,
        extras: [...formData.extras, extra]
      });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    try {
      const bookingData = {
        carId: car._id,
        branchId: car.branchId._id,
        ...formData,
        totalPrice
      };

      const bookingRes = await axios.post('http://localhost:5000/api/bookings', bookingData);
      
      const paymentData = {
        bookingId: bookingRes.data.data._id,
        amount: totalPrice,
        paymentMethod: 'credit_card',
        status: 'completed'
      };

      await axios.post('http://localhost:5000/api/payments', paymentData);

      navigate('/my-bookings');
    } catch (err) {
      setError(err.response?.data?.message || 'Booking failed');
    }
  };

  if (loading) return <div className="loading">Loading...</div>;
  if (!car) return <div className="loading">Car not found</div>;

  return (
    <div className="booking-page">
      <div className="container">
        <h1>Complete Your Booking</h1>
        
        <div className="booking-layout">
          <div className="booking-form-section">
            {error && <div className="alert alert-error">{error}</div>}
            
            <form onSubmit={handleSubmit}>
              <div className="card">
                <h3>Rental Details</h3>
                <div className="form-row">
                  <div className="form-group">
                    <label>Pickup Date</label>
                    <input
                      type="datetime-local"
                      name="pickupDate"
                      value={formData.pickupDate}
                      onChange={handleChange}
                      min={new Date().toISOString().slice(0, 16)}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Dropoff Date</label>
                    <input
                      type="datetime-local"
                      name="dropoffDate"
                      value={formData.dropoffDate}
                      onChange={handleChange}
                      min={formData.pickupDate}
                      required
                    />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Pickup Location</label>
                    <input
                      type="text"
                      name="pickupLocation"
                      value={formData.pickupLocation}
                      onChange={handleChange}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Dropoff Location</label>
                    <input
                      type="text"
                      name="dropoffLocation"
                      value={formData.dropoffLocation}
                      onChange={handleChange}
                      required
                    />
                  </div>
                </div>
              </div>

              <div className="card">
                <h3>Optional Extras</h3>
                <div className="extras-list">
                  {extras.map(extra => (
                    <label key={extra.name} className="extra-item">
                      <input
                        type="checkbox"
                        checked={formData.extras.some(e => e.name === extra.name)}
                        onChange={() => handleExtraToggle(extra)}
                      />
                      <span className="extra-name">{extra.name}</span>
                      <span className="extra-price">${extra.price}/day</span>
                    </label>
                  ))}
                </div>
              </div>

              <button type="submit" className="btn btn-primary btn-lg">
                Confirm Booking - ${totalPrice}
              </button>
            </form>
          </div>

          <div className="booking-summary">
            <div className="card">
              <h3>Booking Summary</h3>
              <div className="summary-car">
                <img src={car.images[0] || '/placeholder-car.jpg'} alt={car.make} />
                <div>
                  <h4>{car.make} {car.model}</h4>
                  <p>{car.year}</p>
                </div>
              </div>
              <div className="summary-details">
                <div className="summary-row">
                  <span>Daily Rate</span>
                  <span>${car.pricePerDay}</span>
                </div>
                {formData.extras.map(extra => (
                  <div key={extra.name} className="summary-row">
                    <span>{extra.name}</span>
                    <span>${extra.price}/day</span>
                  </div>
                ))}
                <div className="summary-row total">
                  <span>Total</span>
                  <span>${totalPrice}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Booking;
